# Cross-validation of causatr variance estimators against external references:
#
# 1. stdReg2 comparison  — point-treatment sandwich vs independent implementation
# 2. Tightened bootstrap — sandwich ≈ bootstrap with large n, tight tolerance
# 3. Hand-computed SEs    — manual J V_β J' and delta method verification
# 4. ICE analytical       — ICE sandwich matches single-model sandwich (no feedback)
# 5. delicatessen refs    — ICE sandwich vs hard-coded values from Python
#
# Reference values in section 5 were generated by data-raw/zepid_reference.py
# using delicatessen (Zivich 2022) for stacked M-estimation sandwich variance.


# ── 1. stdReg2 comparison ────────────────────────────────────────────────────

test_that("gcomp sandwich matches stdReg2 — continuous outcome (DGP 1)", {
  df <- simulate_binary_continuous(n = 5000, seed = 123)

  fit <- causat(df, outcome = "Y", treatment = "A", confounders = ~L)
  res <- contrast(
    fit,
    interventions = list(a1 = static(1), a0 = static(0)),
    reference = "a0",
    ci_method = "sandwich"
  )

  std_fit <- stdReg2::standardize_glm(
    Y ~ A + L,
    data = df,
    values = list(A = c(1, 0)),
    contrasts = "difference",
    reference = 0
  )
  std_res <- generics::tidy(std_fit)
  std_means <- std_res[std_res$contrast == "none", ]
  std_diff <- std_res[std_res$contrast == "difference" & std_res$A == 1, ]

  expect_equal(
    res$estimates$estimate[res$estimates$intervention == "a1"],
    std_means$Estimate[std_means$A == 1],
    tolerance = 1e-6
  )
  expect_equal(
    res$estimates$estimate[res$estimates$intervention == "a0"],
    std_means$Estimate[std_means$A == 0],
    tolerance = 1e-6
  )

  expect_equal(
    res$estimates$se[res$estimates$intervention == "a1"],
    std_means$Std.Error[std_means$A == 1],
    tolerance = 0.01
  )
  expect_equal(
    res$estimates$se[res$estimates$intervention == "a0"],
    std_means$Std.Error[std_means$A == 0],
    tolerance = 0.01
  )

  expect_equal(res$contrasts$estimate[1], std_diff$Estimate, tolerance = 1e-6)
  expect_equal(res$contrasts$se[1], std_diff$Std.Error, tolerance = 0.01)
})


