test_that("gcomp sandwich matches stdReg2 — binary outcome, RR (DGP 2)", {
  df <- simulate_binary_binary(n = 5000, seed = 456)

  fit <- causat(
    df,
    outcome = "Y",
    treatment = "A",
    confounders = ~L,
    family = binomial()
  )
  res <- contrast(
    fit,
    interventions = list(a1 = static(1), a0 = static(0)),
    reference = "a0",
    type = "ratio",
    ci_method = "sandwich"
  )

  std_fit <- stdReg2::standardize_glm(
    Y ~ A + L,
    data = df,
    family = "binomial",
    values = list(A = c(1, 0)),
    contrasts = "ratio",
    reference = 0
  )
  std_res <- generics::tidy(std_fit)
  std_ratio <- std_res[std_res$contrast == "ratio" & std_res$A == 1, ]

  expect_equal(res$contrasts$estimate[1], std_ratio$Estimate, tolerance = 1e-6)

  causatr_se_log <- res$contrasts$se[1] / res$contrasts$estimate[1]
