  expect_equal(causatr_se_log, std_z, tolerance = 0.05)
})


test_that("gcomp sandwich matches stdReg2 — NHEFS (Hernán & Robins)", {
  data("nhefs", package = "causatr")

  nhefs_cc <- nhefs[!is.na(nhefs$wt82_71) & !is.na(nhefs$education), ]

  confounders <- ~ sex + age + I(age^2) + race +
    factor(education) + smokeintensity + I(smokeintensity^2) +
    smokeyrs + I(smokeyrs^2) + factor(exercise) +
    factor(active) + wt71 + I(wt71^2) + qsmk:smokeintensity

  fit <- causat(
    nhefs_cc,
    outcome = "wt82_71",
    treatment = "qsmk",
    confounders = confounders
  )
  res <- contrast(
    fit,
    interventions = list(quit = static(1), cont = static(0)),
    reference = "cont",
    ci_method = "sandwich"
  )

  std_fit <- stdReg2::standardize_glm(
    wt82_71 ~ qsmk + sex + age + I(age^2) + race +
      factor(education) + smokeintensity + I(smokeintensity^2) +
      smokeyrs + I(smokeyrs^2) + factor(exercise) +
      factor(active) + wt71 + I(wt71^2) + qsmk:smokeintensity,
    data = nhefs_cc,
    values = list(qsmk = c(1, 0)),
    contrasts = "difference",
    reference = 0
  )
  std_res <- generics::tidy(std_fit)
  std_means <- std_res[std_res$contrast == "none", ]
  std_diff <- std_res[std_res$contrast == "difference" & std_res$qsmk == 1, ]

  expect_equal(
    res$estimates$estimate[res$estimates$intervention == "quit"],
    std_means$Estimate[std_means$qsmk == 1],
    tolerance = 1e-6
  )
  expect_equal(
    res$estimates$estimate[res$estimates$intervention == "cont"],
    std_means$Estimate[std_means$qsmk == 0],
    tolerance = 1e-6
  )
  expect_equal(
    res$estimates$se[res$estimates$intervention == "quit"],
    std_means$Std.Error[std_means$qsmk == 1],
    tolerance = 0.02
  )
  expect_equal(res$contrasts$se[1], std_diff$Std.Error, tolerance = 0.02)
})


# ── 2. Tightened bootstrap-sandwich agreement ────────────────────────────────

test_that("point gcomp: sandwich ≈ bootstrap within 15% (continuous, large n)", {
  skip_on_os("windows")
  df <- simulate_binary_continuous(n = 5000, seed = 700)

  fit <- causat(df, outcome = "Y", treatment = "A", confounders = ~L)

  res_sw <- contrast(
    fit,
    interventions = list(a1 = static(1), a0 = static(0)),
    reference = "a0",
    ci_method = "sandwich"
  )
  res_bt <- contrast(
    fit,
    interventions = list(a1 = static(1), a0 = static(0)),
    reference = "a0",
    ci_method = "bootstrap",
    n_boot = 300L,
    parallel = "multicore",
    ncpus = 2L
  )

  for (iv in c("a1", "a0")) {
    se_sw <- res_sw$estimates$se[res_sw$estimates$intervention == iv]
    se_bt <- res_bt$estimates$se[res_bt$estimates$intervention == iv]
    ratio <- se_bt / se_sw
    expect_gt(ratio, 0.85, label = paste(iv, "ratio lower"))
    expect_lt(ratio, 1.15, label = paste(iv, "ratio upper"))
  }

  ratio_c <- res_bt$contrasts$se[1] / res_sw$contrasts$se[1]
  expect_gt(ratio_c, 0.85)
  expect_lt(ratio_c, 1.15)
})


