  Y <- rbinom(n, 1, plogis(-2 + 0.8 * A0 + 0.8 * A1 + 0.5 * L0 + 0.3 * L1))

  long <- rbind(
    data.frame(
      id = 1:n, time = 0L, A = A0,
      L = NA_real_, L0 = L0, Y = NA_real_
    ),
    data.frame(id = 1:n, time = 1L, A = A1, L = L1, L0 = L0, Y = Y)
  )

  fit <- causat(
    long,
    outcome = "Y",
    treatment = "A",
    confounders = ~L0,
    confounders_tv = ~L,
    id = "id",
    time = "time",
    family = binomial()
  )
  res <- contrast(
    fit,
    interventions = list(always = static(1), never = static(0)),
    reference = "never",
    ci_method = "sandwich"
  )

